//BT JAMMER .INO: https://github.com/Mxtiv/BlueJammer/blob/main/BlueJammer.ino
// NRF24L01+ PA/LNA & ESP32-WROOM
// Switch (Optional)
// (Can be used to change between modes of jamming)

// Electrolytic Capacitor (10µF – 100µF)
// (Used to stabilize the power supply to the NRF24 module)

#include "RF24.h"
#include <ezButton.h>
#include "esp_bt.h"
#include "esp_wifi.h"

SPIClass *sp = nullptr;

//HSPI=SCK = 14, MISO = 12, MOSI = 13, CS = 15 , CE = 16
//VSPI=SCK = 18, MISO =19, MOSI = 23 ,CS =21 ,CE = 22


RF24 radio(22, 21, 16000000);  ///DEFAULT 10000000

byte i = 45;  ///37-50 CHANNEL (CHANNEL NRF NEEDS TO START )

unsigned int flag = 0;


ezButton toggleSwitch(33);


void initSP() {
  sp = new SPIClass(VSPI);
  sp->begin();
  if (radio.begin(sp)) {
    delay(1000);
    Serial.println("Sp Started !!!");
    radio.setAutoAck(false);
    radio.stopListening();
    radio.setRetries(0, 0);
    radio.setPayloadSize(5);   ////SET VALUE ON RF24.CPP
    radio.setAddressWidth(3);  ////SET VALUE ON RF24.CPP
    radio.setPALevel(RF24_PA_MAX, true);
    radio.setDataRate(RF24_2MBPS);
    radio.setCRCLength(RF24_CRC_DISABLED);
    radio.printPrettyDetails();
    radio.startConstCarrier(RF24_PA_MAX, i);  ////EDITED VALUES ON LIBRARY ....SET 5 BYTES PAYLOAD SIZE//REDUCE RF24_MAX TO RF24_HIGH OR LOW IF RF NOT STABLE



  } else {
    Serial.println("SP couldn't start !!!");
  }
}
void two() {

  ///CHANNEL WITH 2 SPACING HOPPING
  if (flag == 0) {
    i += 2;
  } else {
    i -= 2;
  }

  if ((i > 79) && (flag == 0)) {
    flag = 1;
  } else if ((i < 2) && (flag == 1)) {
    flag = 0;
  }

  radio.setChannel(i);
  // Serial.println(i);
}

void one() {
  for (int i = 0; i < 15; i++) {
    radio.setChannel(i);
  }
}

// radio.setChannel(random(79));




void setup(void) {
  pinMode(33, INPUT_PULLUP);  // BUILD-IN RESISTOR
  esp_bt_controller_deinit();
  esp_wifi_stop();
  esp_wifi_deinit();
  Serial.begin(115200);
  delay(1000);
  Serial.println("Setup started...");
  toggleSwitch.setDebounceTime(50);
  initSP();
}


void loop(void) {

  toggleSwitch.loop();  // MUST call the loop() function first

  if (toggleSwitch.isPressed())
    Serial.println("one");
  if (toggleSwitch.isReleased())
    Serial.println("two");

  int state = toggleSwitch.getState();


  if (state == HIGH)
    two();

  else {
    one();
  }
}

new Vue({
  el: "#app",
  data() {
    return {
      series: [{
        name: 'Likes',
        data: [0.1, 3, 10, 9, 29, 19, 22, 9, 12, 7000],
        color: "#FFF" // serie color
      }],
      chartOptions: {
        chart: {
          height: 600,
          type: 'bar',
          foreColor: '#FFFFFF88',
          fontFamily: 'Montserrat, sans-serif',
           toolbar: {
            show: false
          },
        },
        tooltip: {
    intersect: false, // Tooltip only shows when mouse "intersects" the point
    shared: true    // Usually set to false when intersect is true
  },
        plotOptions: {
          bar: {
            horizontal: true,
            /* rangeBarOverlap: true, */
             borderRadius: 2,
            barHeight: '20',
          },
        },
        stroke: {
          width: 0,
          curve: 'smooth'
        },
       
        fill: {
          type: 'gradient',
          colors:['#FFF'],
          gradient: {
            shade: 'dark',
            shadeIntensity: 1,
            type: 'vertical',
            gradientToColors: [ '#000'],
            opacityFrom: 1,
            opacityTo: 1,
            stops: [0, 100,100,100]
          },
        },      
         yaxis: {
          min: 0,
          max: 100,
          lines: {
            show: false,
          },
        },
        xaxis: {
         	min: 0,
          max: 500,
          color:'#FFF',
          lines: {
            show: false,
          },
        },
      },
    }
  },
 
  components: {
    VueApexCharts
  }
})

